/**
 * Get a random exercise for a given section
 */
export function getRandomExercise(section: 'A' | 'B' | 'C'): TEFExercise {
  const sectionExercises = EXERCISES[section];
  const index = Math.floor(Math.random() * sectionExercises.length);
  return sectionExercises[index];
}

/**
 * Get a specific exercise by section and ID
 */
export function getExerciseById(section: 'A' | 'B' | 'C', id: number): TEFExercise | undefined {
  return EXERCISES[section].find((ex) => ex.id === id);
}
